import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import {
  Trash2,
  Download,
  Archive,
  Calendar,
  ShieldCheck,
  Eye,
  X,
  BarChart3,
  AlignLeft
} from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── Fetch History ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      const data = res.data?.data || res.data || [];
      setHistory(data.filter(item => item && item.id));
    } catch {
      toast.error('VAULT_SYNC_ERROR: UNABLE_TO_REACH_DATABASE');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ───────── Delete Strategy ───────── */
  const handleDelete = async (id) => {
    if (!window.confirm('This strategy will be permanently deleted. Continue?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success('DATA_PURGE_SUCCESSFUL');
    } catch {
      toast.error('WIPE_FAILURE: DATA_PROTECTED_BY_SYSTEM');
    }
  };

  /* ───────── Export PDF ───────── */
  const handleDownload = async (item) => {
    try {
      const res = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const blob = new Blob([res.data], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = url;
      link.download = `Finify_Strategy_${item.id}.pdf`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      URL.revokeObjectURL(url);
    } catch {
      toast.error('EXPORT_FAILED: GENERATION_ERROR');
    }
  };

  /* ───────── Lock Scroll When Modal Open ───────── */
  useEffect(() => {
    document.body.style.overflow = selectedItem ? 'hidden' : 'auto';
    return () => (document.body.style.overflow = 'auto');
  }, [selectedItem]);

  if (loading) {
    return <div style={centerStyle}>SYNCHRONIZING STRATEGY VAULT…</div>;
  }

  return (
    <div style={containerStyle}>
      {/* Header */}
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={32} /> Strategy Vault
        </h2>
        <div style={vaultBadge}>
          <BarChart3 size={16} /> {history.length} Nodes
        </div>
      </div>

      {/* List */}
      <div style={listStyle}>
        {history.length === 0 && (
          <div style={emptyState}>No saved strategies found.</div>
        )}

        {history.map(item => (
          <div key={item.id} style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '20px' }}>
                <span style={dateTag}>
                  <Calendar size={14} />
                  {new Date(item.created_at).toLocaleDateString()}
                </span>
                <span style={riskTag}>
                  <ShieldCheck size={14} />
                  Risk: {item.risk_score ?? 'N/A'}
                </span>
              </div>

              <div style={cardActions}>
                <button style={iconBtn} onClick={() => setSelectedItem(item)}>
                  <Eye size={20} />
                </button>
                <button style={iconBtn} onClick={() => handleDownload(item)}>
                  <Download size={20} />
                </button>
                <button style={deleteBtn} onClick={() => handleDelete(item.id)}>
                  <Trash2 size={20} />
                </button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal || 'Untitled Strategy'}</h4>

            <p style={labelSmall}>
              <AlignLeft size={12} /> Summary
            </p>

            <ReactMarkdown>
              {item.summary || '_No summary available._'}
            </ReactMarkdown>
          </div>
        ))}
      </div>

      {/* Modal */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent(isDark)}>
            <div style={modalHeader}>
              <span style={modalId}>Strategy #{selectedItem.id}</span>
              <button style={closeBtn} onClick={() => setSelectedItem(null)}>
                <X size={24} />
              </button>
            </div>

            <div style={modalBody}>
              <h3 style={modalTitle}>
                {selectedItem.goal || 'Untitled Strategy'}
              </h3>

              <p style={labelSmall}>
                <AlignLeft size={14} /> Rationale
              </p>

              {selectedItem.rationale ? (
                <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
              ) : (
                <p style={{ opacity: 0.6, fontStyle: 'italic' }}>
                  No detailed reasoning was stored for this strategy.
                </p>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ───────── Styles (Normalized Text Size) ───────── */

const containerStyle = { padding: '3rem 1.5rem', maxWidth: '1200px', margin: '0 auto' };
const headerRow = { display: 'flex', justifyContent: 'space-between', marginBottom: '2.5rem' };
const headerStyle = { display: 'flex', gap: '12px', fontSize: '1.8rem', fontWeight: 800 };
const vaultBadge = { display: 'flex', gap: '8px', fontWeight: 700, fontSize: '0.85rem' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '2rem' };
const cardStyle = { padding: '2rem', borderRadius: '20px', border: '1px solid var(--surface-border)' };
const cardMeta = { display: 'flex', justifyContent: 'space-between', marginBottom: '1.2rem' };
const dateTag = { fontSize: '0.85rem', display: 'flex', gap: '6px' };
const riskTag = { fontSize: '0.85rem', display: 'flex', gap: '6px', fontWeight: 600 };
const cardActions = { display: 'flex', gap: '12px' };
const iconBtn = { background: 'none', border: 'none', cursor: 'pointer' };
const deleteBtn = { ...iconBtn, color: '#ef4444' };
const titleStyle = { fontSize: '1.3rem', fontWeight: 700, marginBottom: '1rem' };
const labelSmall = { fontSize: '0.75rem', fontWeight: 700, opacity: 0.7, marginBottom: '0.5rem' };
const emptyState = { textAlign: 'center', opacity: 0.6 };
const centerStyle = { height: '70vh', display: 'flex', justifyContent: 'center', alignItems: 'center' };

const modalOverlay = isDark => ({
  position: 'fixed',
  inset: 0,
  background: isDark ? 'rgba(0,0,0,0.9)' : 'rgba(255,255,255,0.9)',
  display: 'flex',
  justifyContent: 'center',
  alignItems: 'center',
  zIndex: 2000
});

const modalContent = isDark => ({
  width: '90%',
  maxWidth: '900px',
  background: isDark ? '#000' : '#fff',
  borderRadius: '20px'
});

const modalHeader = { padding: '1.5rem', display: 'flex', justifyContent: 'space-between' };
const modalId = { fontWeight: 700, fontSize: '0.85rem' };
const modalBody = { padding: '2rem', maxHeight: '70vh', overflowY: 'auto' };
const modalTitle = { fontSize: '1.6rem', fontWeight: 800, marginBottom: '1.5rem' };
const closeBtn = { background: 'none', border: 'none', cursor: 'pointer' };

export default VaultPage;
